#!/bin/bash

mkdir -p bw

# Create a simple color image
echo '' | base64 -d > color-penguin.png

# Convert to grayscale and save as BW versions
convert color-penguin.png -colorspace gray bw-penguin.png

# Create each penguin species image
species=(
    "little-blue-penguin"
    "fairy-penguin"
    "rockhopper-penguin"
    "adelie-penguin"
    "galapagos-penguin"
    "chinstrap-penguin"
    "gentoo-penguin" 
    "yellow-eyed-penguin"
    "macaroni-penguin"
    "fiordland-penguin"
    "snares-penguin"
    "humboldt-penguin"
    "magellanic-penguin"
    "african-penguin"
    "royal-penguin"
    "king-penguin"
    "emperor-penguin"
)

# Copy the base image to all species filenames
for species in "${species[@]}"; do
    cp color-penguin.png "${species}.jpg"
    cp bw-penguin.png "bw/${species}-bw.jpg"
done

echo "All images created successfully"